var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 아파!! 도와줘요!!","JPN":"い、痛い！！　助けてください！！","ENG":"Ow! That hurts! Help!","TWN":"痛，好痛！救救我！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아! 내, 내 손! 내 손이!!","JPN":"うわあ！　ぼ、ぼくの手！　ぼくの手が！！","ENG":"Aaah! My hand! My hand!","TWN":"啊！我的手！我的手啊！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"괴, 괴물이야!!","JPN":"ば、化け物だ！！","ENG":"M-monsters!","TWN":"怪，怪物啊！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이봐, 무슨 소리 하는 거야! 저건 사람이라고!","JPN":"ちょっと、何言ってるの！　あれは人間だって！","ENG":"What are you talking about?! That’s a person!","TWN":"喂，這是什麼聲音啊！那個是人嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배? 보고 있어? 사람들 상태가 이상해!","JPN":"先輩、見てる？　みんなの様子がおかしい！","ENG":"Shiyoon? Are you seeing this? Everyone’s acting weird!","TWN":"前輩，你看到了嗎？人們的樣子好奇怪。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......아무래도 급성 침식 증후군 같군요.","JPN":"……どうやら、急性侵食症候群みたいですね。","ENG":"It appears to be a case of acute Corruption Syndrome.","TWN":"……像是急性侵蝕症候群。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이상하네요.","JPN":"だけど、おかしいですね。","ENG":"But that’s odd...","TWN":"但是好奇怪。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런 건 CSE 4 레벨 이상은 되어야 나타나는 현상인데 말이죠.","JPN":"これはCSEレベル4以上にならないと現れない現象なのに。","ENG":"These sort of things only happen when the CSE Level reaches 4 or above.","TWN":"這是達到CSE4級以上才會發生的異常現象啊。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이대로 두면 얼마 지나지 않아서 여기에 있는 사람들 모두 침식체로 변이해 버리고 말 겁니다.","JPN":"このままだと、間もなくここの皆さんが侵食体に変わってしまうでしょう。","ENG":"At this rate, everyone here will become Corrupted Objects.","TWN":"再這樣下去的話，這裡的人都會變成侵蝕體的。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 그러고 보니 미나 양도 잘 알겠군요. 언니가.......","JPN":"あ、そういえばミナさんも詳しいでしょうね、お姉さんが……","ENG":"Oh, I suppose you’re well aware of that already. With your sister...","TWN":"啊，話說回來妳應該很清楚。因為妳姐姐……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるっさいな！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 여긴 침식 안정지대라고!","JPN":"それより、ここは侵食安定地帯なんだよ！","ENG":"Besides, this place is supposed to have stable CSE levels!","TWN":"比起那個，這裡是侵蝕安全地帶！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"CSE 4 레벨 근처에도 못 가는데 침식 증후군이라니, 말이 안 되잖아?","JPN":"CSEレベル4にも達していないのに侵食症候群だなんて、あり得ないでしょ！","ENG":"It's nowhere near CSE Level 4. There's no way these folks could be suffering from Corruption Syndrome!","TWN":"無法達到CSE4級附近區域，哪來的侵蝕症候群，這怎麼可能？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음...... 제 생각엔 아무래도 저게 수상해 보이네요.","JPN":"ふむ……僕が思うに、あれが怪しいですね。","ENG":"Hmm... If I had to guess, that thing looks suspicious to me.","TWN":"嗯……我覺得這件事情怎麼看都很奇怪。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......저 함선이?","JPN":"……あの艦船？","ENG":"You mean that ship?","TWN":"……那艘艦船？"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"침식체들의 등장도 급성 침식 현상도, 모두 저 함선이 추락한 직후에 벌어지기 시작했으니까요.","JPN":"侵食体の登場も、急性侵食現象も、あの艦船が墜落した直後から起こってますからね。","ENG":"These C.O.'s and the acute Corruption Syndrome all appeared right after that ship crashed.","TWN":"不管是侵蝕體突然出現，還是急性侵蝕現象，都是在艦船墜落以後發生的。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우연이라기엔 참 공교롭죠.","JPN":"偶然にしては出来すぎています。","ENG":"It simply can’t be a coincidence.","TWN":"這也太巧了吧。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"거기에다 아직 살아남은 침식체들의 움직임을 좀 보세요.","JPN":"それに、まだ生き残っている侵食体の動きを見てください。","ENG":"Plus, look at how the surviving C.O.'s are moving.","TWN":"妳看那邊還活著的侵蝕體。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"모두 저 함선을 중심으로 모여들고 있어요.","JPN":"すべてあの艦船を中心に集まっています。","ENG":"They’re all gathering around the ship.","TWN":"它們全部都在向艦船聚集。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......마치, 뭔가를 지키는 것처럼 말이죠.","JPN":"……まるで、何かを守るように。","ENG":"As if... they're trying to protect something.","TWN":"……就像在守護著什麼一樣。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"확실하진 않지만 저 함선.......","JPN":"確証はありませんが、あの艦船は……","ENG":"I can’t be certain... but that ship...","TWN":"雖然不確定，但是那艘艦船……"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도 어떤 식으로든 지금 벌어지고 있는 일과 관련이 있을 겁니다.","JPN":"どんな形であれ、今起きている現象と関連があるでしょうね。","ENG":"It probably has something to do with what’s happening here.","TWN":"應該與現在正在發生的事情有著某種關聯。"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"과연.......","JPN":"なるほどね……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"MAINSTREAM_412010","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 뭘 망설이고 있는 거야?","JPN":"だったら、何をためらっているの？","ENG":"Well, what are we waiting for?","TWN":"那我們在猶豫什麼？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......네?","JPN":"……はい？","ENG":"...Sorry?","TWN":"……嗯？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당장 저걸 박살내 버려야지!","JPN":"今すぐあれをぶち壊すのみでしょ！","ENG":"We should smash that thing to bits right away!","TWN":"要立刻毀掉那個東西啊！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니, 확실한 건 아니라니까요?","JPN":"いや、ですから、確証はないんですよ？","ENG":"Like I said, I can’t be certain...","TWN":"不，因為這不是確定的事情啊？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 애초에 때려부순다고 해결된다는 보장도 없어요.","JPN":"それに、ぶち壊したところで解決するとは限りません。","ENG":"Besides, there's no guarantee that smashing the ship would solve anything.","TWN":"而且也不是摧毀它就能解決問題。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무슨 인간 불도저도 아니고, 뭐든 그렇게 폭력적으로 해결하려고만 하면.......","JPN":"ブルドーザーじゃあるまいし、なんでもかんでも力で解決しようとすると……","ENG":"You can’t just bulldoze your way through every problem like that...","TWN":"又不是什麼人肉推土機，不是什麼事情都能用暴力來解決………"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양?","JPN":"ミナさん？","ENG":"Mina?","TWN":"米娜小姐？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양!! 제 말 좀 듣고 가요!","JPN":"ミナさん！！　僕の話、終わってないですよ！","ENG":"Mina! Hear me out first!","TWN":"米娜小姐！妳有在聽我說嗎！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하아, 이것 참. 정말 곤란한 분이시라니까요.","JPN":"はあ、本当に困った人ですね。","ENG":"Haha, oh my. She really is a handful, isn’t she...","TWN":"唉……這可真是……真是個讓人頭痛的人呢。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"거기다가 이런 불길한 느낌......","JPN":"それにこの不吉な感じ……","ENG":"Worse yet, I’ve got this ominous feeling...","TWN":"再加上，這種不祥的感覺……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어쩐지 예감이 좋지 않은데 말이죠.","JPN":"なんだか、イヤな予感がするんですよね。","ENG":"Yup... I've got a bad feeling about this.","TWN":"總覺得有種不好的預感。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};